Here's a C++ program that sorts a given array in descending order using the merge sort algorithm, removes duplicate values, and utilizes multithreading to improve performance:

```cpp
#include <iostream>
#include <vector>
#include <thread>

const int MAX_VALUE = 1000;
const int MIN_VALUE = -1000;

void merge(std::vector<int>& arr, int left, int mid, int right) {
    int n1 = mid - left + 1;
    int n2 = right - mid;

    std::vector<int> leftArr(n1), rightArr(n2);

    for (int i = 0; i < n1; i++)
        leftArr[i] = arr[left + i];
    for (int j = 0; j < n2; j++)
        rightArr[j] = arr[mid + 1 + j];

    int i = 0, j = 0, k = left;

    while (i < n1 && j < n2) {
        if (leftArr[i] >= rightArr[j])
            arr[k++] = leftArr[i++];
        else
            arr[k++] = rightArr[j++];
    }

    while (i < n1)
        arr[k++] = leftArr[i++];

    while (j < n2)
        arr[k++] = rightArr[j++];
}

void mergeSort(std::vector<int>& arr, int left, int right) {
    if (left >= right)
        return;

    int mid = left + (right - left) / 2;

    std::thread t1(mergeSort, std::ref(arr), left, mid);
    std::thread t2(mergeSort, std::ref(arr), mid + 1, right);

    t1.join();
    t2.join();

    merge(arr, left, mid, right);
}

void removeDuplicates(std::vector<int>& arr) {
    std::vector<int>::iterator it = std::unique(arr.begin(), arr.end());
    arr.resize(std::distance(arr.begin(), it));
}

int main() {
    int n;
    std::cout << "Enter the number of elements: ";
    std::cin >> n;

    std::vector<int> arr(n);

    std::cout << "Enter the elements:\n";
    for (int i = 0; i < n; i++)
        std::cin >> arr[i];

    mergeSort(arr, 0, n - 1);
    removeDuplicates(arr);

    std::cout << "Sorted array without duplicates in descending order:\n";
    for (int i = arr.size() - 1; i >= 0; i--)
        std::cout << arr[i] << " ";

    return 0;
}
